/**
 * Gera cobrança simulada (PIX ou boleto) determinística por tarefa.
 *
 * Em produção esse workflow chamaria sua API de pagamentos favorita
 * e retornaria link de pagamento real. Aqui devolvemos um
 * `transactionId` previsível para que o WF 05 Emitir Apólice possa
 * confirmar o pagamento sem dependência externa.
 */

function __hashHex(input) {
  // Substitui o hash SHA-256 do node crypto.
  // Módulo 'crypto' é bloqueado no task-runner do n8n, então fazemos
  // um hash determinístico em JS puro (8x FNV-1a concatenados = 64 hex chars).
  const str = String(input);
  const seeds = [0x811c9dc5, 0xcbf29ce4, 0xdeadbeef, 0xcafebabe,
                 0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a];
  let out = '';
  for (let round = 0; round < 8; round++) {
    let h = seeds[round];
    for (let i = 0; i < str.length; i++) {
      h ^= str.charCodeAt(i) + round;
      h = Math.imul(h, 0x01000193) >>> 0;
    }
    out += h.toString(16).padStart(8, '0');
  }
  return out;
}
const input = $input.first().json;

const obrigatorios = ['task_id', 'valor', 'metodo'];
for (const campo of obrigatorios) {
  if (input[campo] === undefined || input[campo] === null || input[campo] === '') {
    throw new Error(`Campo obrigatório ausente: ${campo}`);
  }
}

const metodosValidos = ['pix', 'boleto'];
const metodo = String(input.metodo).toLowerCase();
if (!metodosValidos.includes(metodo)) {
  throw new Error(`metodo inválido. Use: ${metodosValidos.join(', ')}`);
}

const valorCentavos = Math.round(Number(input.valor) * 100);
if (!Number.isFinite(valorCentavos) || valorCentavos <= 0) {
  throw new Error('valor deve ser um número positivo.');
}

const seedStr = `${input.task_id}|${metodo}|${valorCentavos}`;
const hash = __hashHex(seedStr);
const transactionId = `txn_${hash.slice(0, 24)}`;

const valorFmt = (valorCentavos / 100).toFixed(2);
const vencimento = DateTime.now().plus({ days: 3 }).toISODate();

let link_pagamento;
let instrucao;
let qr_code = null;
let boleto_linha = null;

if (metodo === 'pix') {
  qr_code = `00020126${hash.slice(0, 20).toUpperCase()}5204000053039865405${valorFmt}5802BR5915MOCK CORRETORA6009SAO PAULO62070503***6304${hash.slice(0, 4).toUpperCase()}`;
  link_pagamento = `https://mock.corretora/pagar/pix/${transactionId}`;
  instrucao = '💸 *Pagamento via PIX*\n\n' +
    `Valor: R$ ${valorFmt}\n` +
    `Vencimento: ${vencimento}\n\n` +
    `Chave PIX (copia e cola):\n\`\`\`\n${qr_code}\n\`\`\`\n\n` +
    `Ou pague pelo link: ${link_pagamento}`;
} else {
  boleto_linha = `34191.${hash.slice(0,5)}.${hash.slice(5,11)} ${hash.slice(11,16)}.${hash.slice(16,22)} ${hash.slice(22,28)}.${hash.slice(28,30)} 9 ${Math.floor(valorCentavos).toString().padStart(14,'0')}`;
  link_pagamento = `https://mock.corretora/pagar/boleto/${transactionId}`;
  instrucao = '💳 *Boleto gerado*\n\n' +
    `Valor: R$ ${valorFmt}\n` +
    `Vencimento: ${vencimento}\n\n` +
    `Linha digitável:\n\`\`\`\n${boleto_linha}\n\`\`\`\n\n` +
    `Download: ${link_pagamento}`;
}

return [{
  json: {
    transactionId,
    metodo,
    valor: Number(valorFmt),
    vencimento,
    link_pagamento,
    qr_code,
    boleto_linha,
    instrucao_cliente: instrucao,
    status: 'CONFIRMED',
    descricao: input.descricao || `Mensalidade do plano de saúde`,
    // No mock o pagamento é confirmado imediatamente.
    paidAt: DateTime.now().toISO()
  }
}];
